#include <stdio.h>

long long factorial(int n) {
    return (n <= 1) ? 1 : (long long)n * factorial(n - 1);
}

int main(void) {
    int n = 5;
    printf("Factorial of %d = %lld\n", n, factorial(n));
    return 0;
}

